/** Where the receipt / source document for a mismatch row currently stands. */
export type ReceiptState = "attached" | "missing";

/**
 * The shape of a mismatch:
 * - `fee-only`        — on the statement only; a fee/drift the ledger missed.
 *                       Fix = add it to the ledger.
 * - `in-transit`      — in the ledger, not yet on the statement (real, not
 *                       cleared). Fix = mark in-transit so it isn't "missing".
 * - `amount-mismatch` — both sides have it, but the amounts differ.
 *                       Fix = accept the statement amount.
 */
export type MismatchType = "fee-only" | "in-transit" | "amount-mismatch";

/** Status-dot tone for an unresolved row (resolved rows always read green). */
export type MismatchTone = "extra" | "miss";

/** The uploaded statement — the operator's custody (§6). */
export interface StatementSource {
  /** e.g. "Bangkok Bank statement — May 2026". */
  name: string;
  /** Period label echoed in the source bar + reconciliation name. */
  period: string;
  /** Statement line count. */
  lines: number;
  /** Custody framing — verbatim from the template/spec. */
  custody: string;
}

/** One mismatch row in "What doesn't line up". */
export interface MismatchRow {
  /** Stable key for React + resolve state. */
  key: string;
  type: MismatchType;
  /** Status-dot tone while unresolved. */
  tone: MismatchTone;
  /** "In your ledger" cell — primary line. */
  led: string;
  /** "In your ledger" cell — mono sub-line. */
  ledSub: string;
  /** "On the statement" cell. */
  stmt: string;
  /** Amount column (mono, signed/delta as given). */
  amt: string;
  /** Receipt / source-document state for the row. */
  receipt: ReceiptState;
  /** Magellan's match-confidence for the row (0–100). */
  conf: number;
  /** The unresolved status chip label. */
  flag: string;
  /** The inline-fix button label (resolves the row in place). */
  fix: string;
  /** The status chip label once resolved. */
  resolvedFlag: string;
  /** Plain-language note (kept for parity / future expansion). */
  note: string;
}

