"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeReconcile — the Finance "match" surface: reconcile the ledger against
   the bank/Stripe statement the operator uploaded, flag + fix what doesn't
   line up, and keep the statement as proof for the accountant.

   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Finance/
   magellan-finance-reconcile.html (Finance model spec §8.5 + §6).

   Reconcile = "Receive's matching half": Magellan auto-matches on date +
   amount, then payee, and surfaces only the lines that don't line up.

   Composition:
   - page-head (shared bridge-page-head)
   - statement-source custody bar (bridge-rcl-source) — uploaded, kept as the
     reconciliation source; "Magellan never touches your bank" (§6)
   - match summary (shared bridge-rb-sku) — matched / need-attention / %
     reconciled, recomputed live from row state
   - "What doesn't line up" table (bridge-rcl-table): per-row status DOTS
     (extra / not-cleared / amount-differs), receipt + match-confidence chips,
     and an inline "— fix" affordance that resolves the row in place
   - resolving all → 100% → commit unlocks (like CloseMonth's blockers → READY)
   - two-tier consequence read (shared bridge-ni-outcome*) computed from the
     current row state: *this reconciliation* + *for the handoff*
   - commit (shared bridge-ni-commit) — "Reconcile May → / Resolve N to
     reconcile →" gated on all-resolved, with done state

   Honesty doctrine (§6): the statement is the operator's custody; Magellan
   reconciles against the file you bring — no bank connection. Reversible.
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  STATEMENT_SOURCE,
  MISMATCH_ROWS,
  LEDGER_TOTAL,
  AUTO_MATCHED,
  CASH_POSITION,
  DRIFT_CAUGHT,
  type ReceiptState,
} from "@/features/finance/api/finance-reconcile-data";
import "./BridgeReconcile.css";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;

export function BridgeReconcile() {
  const { setPage } = useBridge();

  // Which mismatch rows have been resolved (by key) in demo state.
  const [resolved, setResolved] = useState<Record<string, boolean>>({});
  const [committed, setCommitted] = useState(false);
  const [committing, setCommitting] = useState(false);

  const resolveRow = (key: string) =>
    setResolved((r) => ({ ...r, [key]: true }));

  /* ─── Live read — recomputed from row state (§5) ─── */
  const read = useMemo(() => {
    const open = MISMATCH_ROWS.filter((row) => !resolved[row.key]).length;
    const total = MISMATCH_ROWS.length;
    const resolvedCount = total - open;
    // Auto-matched grows as each surfaced line is resolved.
    const matched = AUTO_MATCHED + resolvedCount;

    // % reconciled: 100% only when nothing is open; otherwise rounded.
    const rate =
      open === 0 ? 100 : Math.round((matched / LEDGER_TOTAL) * 100);

    return {
      open,
      total,
      resolvedCount,
      matched,
      rate,
      reconciled: open === 0,
    };
  }, [resolved]);

  const commit = () => {
    if (!read.reconciled || committed || committing) return;
    setCommitting(true);
    setTimeout(() => {
      setCommitting(false);
      setCommitted(true);
    }, 700);
  };

  const recCell = (receipt: ReceiptState) =>
    receipt === "attached" ? (
      <span className="bridge-rcl-receipt attached">
        <svg viewBox="0 0 24 24">
          <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" />
        </svg>
        attached
      </span>
    ) : (
      <span className="bridge-rcl-receipt missing">no receipt</span>
    );

  return (
    <div className="bridge-content">
      {/* Page header */}
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M4 7 h7 M4 7 l2 -2 M4 7 l2 2" />
            <path d="M20 17 h-7 M20 17 l-2 -2 M20 17 l-2 2" />
            <path d="M11 7 a5 5 0 0 1 5 5 M13 17 a5 5 0 0 1 -5 -5" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Reconcile</div>
          <div className="bridge-page-head-sub">
            Match your ledger against the real bank or Stripe statement. Magellan flags anything that doesn&rsquo;t line up &mdash; and keeps the statement as proof for your accountant. You bring the statement; Magellan never touches your bank.
          </div>
        </div>
      </div>

      {/* The statement source — uploaded, kept as custody (§6) */}
      <div className="bridge-rcl-source">
        <div className="bridge-rcl-source-ic">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M5 4 h11 l3 3 v13 h-14 z" />
            <path d="M9 9 h6 M9 13 h6 M9 17 h4" />
          </svg>
        </div>
        <div className="bridge-rcl-source-body">
          <div className="bridge-rcl-source-title">
            {STATEMENT_SOURCE.name} &mdash; {STATEMENT_SOURCE.period}{" "}
            <span className="bridge-rcl-source-state">&middot; loaded</span>
          </div>
          <div className="bridge-rcl-source-sub">
            {STATEMENT_SOURCE.lines} lines &middot; {STATEMENT_SOURCE.custody}
          </div>
        </div>
        <button className="bridge-rcl-source-act" type="button">
          Use a different statement
        </button>
      </div>

      {/* Match summary — recomputed live from row state */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">{STATEMENT_SOURCE.period.split(" ")[0]} reconciliation</div>
          <div className="bridge-rb-sku-meta">
            ledger vs. statement &middot; matched on date + amount, then payee
          </div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{read.matched}</span>
            <span className="bridge-rb-stat-k">matched</span>
          </div>
          <div className="bridge-rb-stat">
            <span className={`bridge-rb-stat-v${read.open > 0 ? " alert" : ""}`}>
              {read.open}
            </span>
            <span className="bridge-rb-stat-k">need attention</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{read.rate}%</span>
            <span className="bridge-rb-stat-k">reconciled</span>
          </div>
        </div>
      </div>

      {/* The match table — "What doesn't line up" */}
      <div className="bridge-ni-card bridge-rcl-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">What doesn&rsquo;t line up</span>
          <span className="bridge-ni-source manual">
            &#10022; {AUTO_MATCHED} auto-matched &mdash; showing the {read.total} that need you
          </span>
        </div>
        <table className="bridge-rcl-table">
          <thead>
            <tr>
              <th>In your ledger</th>
              <th>On the statement</th>
              <th className="r">Amount</th>
              <th>Receipt</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {MISMATCH_ROWS.map((row) => {
              const isResolved = !!resolved[row.key];
              const dotTone = isResolved ? "match" : row.tone;
              const flagTone = isResolved ? "match" : row.tone;
              return (
                <tr key={row.key} className={`bridge-rcl-row${isResolved ? " done" : ""}`}>
                  <td>
                    <div className="bridge-rcl-led">{row.led}</div>
                    <div className="bridge-rcl-led-sub">{row.ledSub}</div>
                  </td>
                  <td>
                    <span className="bridge-rcl-stmt">{row.stmt}</span>
                  </td>
                  <td className="r bridge-rcl-amt">{row.amt}</td>
                  <td>
                    {recCell(row.receipt)}
                    <div className="bridge-rcl-conf">{row.conf}% match conf.</div>
                  </td>
                  <td>
                    <span className="bridge-rcl-status">
                      <span className={`bridge-rcl-statdot ${dotTone}`} />
                      <span className={`bridge-rcl-flag ${flagTone}`}>
                        {isResolved ? row.resolvedFlag : row.flag}
                      </span>
                    </span>
                    {!isResolved && (
                      <button
                        className="bridge-rcl-fix"
                        type="button"
                        onClick={() => resolveRow(row.key)}
                      >
                        {row.fix} &rarr;
                      </button>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* What reconciling settles — two-tier consequence read */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What reconciling settles
          <span className="bridge-ni-outcome-prov firm">Computed against the statement</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">This reconciliation</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Lines reconciled</span>
              <span className="v good">
                {read.matched} of {LEDGER_TOTAL}
              </span>
              <span className="kk">ledger matches reality</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Still open</span>
              <span className={`v${read.open > 0 ? " alert" : " good"}`}>{read.open}</span>
              <span className="kk">
                {read.open > 0 ? "resolve before close" : "all matched"}
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Cash position confirmed</span>
              <span className="v">{fmtUSD(CASH_POSITION)}</span>
              <span className="kk">matches statement balance</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Drift caught</span>
              <span className="v">{fmtUSD(DRIFT_CAUGHT)}</span>
              <span className="kk">fees the ledger missed</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">For the handoff</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Statement kept</span>
              <span className="v good">attached</span>
              <span className="kk">travels to accountant</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Feeds Close Month</span>
              <span className="v">reconciled stamp</span>
              <span className="kk">the {read.rate}% becomes real</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Bank untouched</span>
              <span className="v">no connection</span>
              <span className="kk">you provided the file</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Audit trail</span>
              <span className="v">ledger + source</span>
              <span className="kk">both on record</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Reconciling proves your ledger matches what actually moved through the account. Magellan matches each entry to a statement line; a charge in your ledger that isn&rsquo;t on the statement (or a statement line with no ledger entry &mdash; usually a fee you missed) gets flagged to fix. The statement you uploaded is <b>kept as the source document</b> and travels with the month-end export. Magellan never connects to your bank &mdash; it reconciles against the file you bring.
        </div>

        <div className="bridge-rcl-tier-path">
          <span className="bridge-rcl-tier-step">
            <span className="bridge-rcl-tdot live" />
            Live
          </span>
          <span className="bridge-rcl-tier-arr">&rarr;</span>
          <span className="bridge-rcl-tier-step">
            <span className="bridge-rcl-tdot est" />
            Estimated
          </span>
          <span className="bridge-rcl-tier-arr">&rarr;</span>
          <span className="bridge-rcl-tier-step now">
            <span className="bridge-rcl-tdot rec" />
            Reconciled
          </span>
          <span className="bridge-rcl-tier-arr">&rarr;</span>
          <span className="bridge-rcl-tier-step">
            <span className="bridge-rcl-tdot app" />
            Accountant-approved
          </span>
          <span className="bridge-rcl-tier-note">
            &mdash; reconciling <b>promotes these entries to Reconciled</b>; your accountant&rsquo;s sign-off in Xero is the last step.
          </span>
        </div>
      </div>

      {/* Commit — unlocks only when everything is resolved */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the reconciliation &mdash; the {read.total} open items <b>aren&rsquo;t resolved</b> until you act on each, then confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Save progress
          </button>
          <button
            className={`bridge-ni-create${committed ? " done" : ""}`}
            type="button"
            onClick={commit}
            disabled={!read.reconciled || committed || committing}
          >
            {committed
              ? `✓ ${STATEMENT_SOURCE.period.split(" ")[0]} reconciled`
              : committing
                ? "Reconciling…"
                : read.reconciled
                  ? `Reconcile ${STATEMENT_SOURCE.period.split(" ")[0]} — all matched →`
                  : `Resolve ${read.open} to reconcile →`}
          </button>
        </div>
      </div>
    </div>
  );
}
